INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('xo ao Decreto-Lei n.º 372/2007, de 6 de novembro, podem ser dispensadas dos pagamentos por conta, definidos pelo disposto nos artigos 105.º a 107.º do Código do IRC.
  2 - As entidades abrangidas pela dispensa prevista no número anterior, que pretendam efetuar o pagamento por conta, podem realizar esse pagamento, nos termos e nos prazos definidos por lei.
