INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('20, de 24 de agosto, que transpõe os artigos 2.º e 3.º da Diretiva (UE) 2017/2455 do Conselho, de 5 de dezembro de 2017, e a Diretiva (UE) 2019/1995 do Conselho, de 21 de novembro de 2019, passam a ter a seguinte redação:
